import React, { useState } from "react";
import Subjects from "../components/Subjects";
import Results from "../components/Results";
import TimeTable from "../components/TimeTable";
import Attendance from "../components/Attendance";
import "../App.css";

function StudentDashboard() {

  const student = JSON.parse(localStorage.getItem("student")) || {
    name: "moushi",
    id: "S12345",
    branch: "ECE"
  };

  const [activePage, setActivePage] = useState("subjects");

  return (

    <div className="dashboard">

      {/* Sidebar */}
      <div className="sidebar">
        <h2>Student Portal</h2>

        <ul>
          <li onClick={() => setActivePage("subjects")}>Subjects</li>
          <li onClick={() => setActivePage("results")}>Results</li>
          <li onClick={() => setActivePage("timetable")}>Time Table</li>
          <li onClick={() => setActivePage("attendance")}>Attendance</li>
        </ul>
      </div>

      {/* Main Area */}
      <div className="main">

        {/* Profile */}
        <div className="profile">
          <img
            src="https://cdn-icons-png.flaticon.com/512/3135/3135715.png"
            alt="student"
          />

          <div>
            <h2>{student.name}</h2>
            <p>ID : {student.id}</p>
            <p>Branch : {student.branch}</p>
          </div>
        </div>

        {/* Dynamic Content */}
        {activePage === "subjects" && <Subjects branch={student.branch} />}
        {activePage === "results" && <Results />}
        {activePage === "timetable" && <TimeTable />}
        {activePage === "attendance" && <Attendance />}

      </div>

    </div>
  );
}

export default StudentDashboard;
